const body = $input.first().json.body ?? $input.first().json;

// Ignorar mensagens enviadas pelo próprio número
if (body.fromMe === true) return [];

// Ignorar grupos
if (body.isGroup === true) return [];

// Extrair texto
const message = body.text?.message ?? body.message?.text ?? body.textMessage ?? '';
if (!message.trim()) return [];

// Normalizar número
let phone = (body.phone ?? '').replace('@c.us', '').replace(/[^0-9]/g, '');
if (!phone) return [];

if (phone.length === 10 || phone.length === 11) phone = '55' + phone;
if (phone.length === 12 && phone.startsWith('55')) {
  phone = phone.slice(0, 4) + '9' + phone.slice(4);
}

return [{ json: {
  phone,
  message: message.trim(),
  senderName: body.senderName ?? body.chatName ?? 'Cliente'
}}];

const incoming = $('Filtrar Mensagem').first().json;
const convData = $input.first().json;

const conversa = Array.isArray(convData) ? (convData.length > 0 ? convData[0] : null) : (convData && convData.phone ? convData : null);

let mensagens = conversa?.mensagens ?? [];
const produtoTitulo = conversa?.produto_titulo ?? '';
const produtoPreco = parseFloat(conversa?.produto_preco ?? 0);
const descontoMax = parseInt(conversa?.desconto_max ?? 0);
const produtoId = conversa?.produto_id ?? null;
const clienteNome = conversa?.cliente_nome || incoming.senderName || '';
const ehSeminovo = conversa?.seminovo === true;
const produtoMarca = conversa?.produto_marca ?? null;
const descricao = conversa?.descricao ?? '';
const specs = conversa?.specs ?? null;

mensagens = [...mensagens, { role: 'user', content: incoming.message }];
if (mensagens.length > 20) mensagens = mensagens.slice(-20);

const cleaned = [];
for (const msg of mensagens) {
  if (cleaned.length === 0 && msg.role !== 'user') continue;
  if (cleaned.length > 0 && msg.role === cleaned[cleaned.length - 1].role) continue;
  cleaned.push(msg);
}

const fmt = (v) => 'R$ ' + parseFloat(v).toFixed(2).replace('.', ',');
const precoFmt = produtoPreco ? fmt(produtoPreco) : 'a confirmar';
const precoMinimo = descontoMax && produtoPreco
  ? fmt(produtoPreco * (1 - descontoMax / 100))
  : null;

const marcaNorm = (produtoMarca || '').toLowerCase();
const ehPousinox = !produtoMarca || marcaNorm === 'pousinox';
const ehTerceiro = marcaNorm === 'outro';
const ehRepresentado = !ehPousinox && !ehTerceiro;

let origemProduto;
if (ehRepresentado) {
  origemProduto = `produto da marca ${produtoMarca}, comercializado pela Pousinox`;
} else if (ehTerceiro) {
  origemProduto = 'equipamento de terceiros (adquirido pela Pousinox — fabricante não divulgado)';
} else {
  origemProduto = 'fabricado pela Pousinox';
}

const estadoProduto = ehSeminovo
  ? `SEMINOVO (usado, em bom estado — ${origemProduto})`
  : `NOVO (${origemProduto})`;

let specsTexto = '';
if (specs) {
  const specsArr = Array.isArray(specs) ? specs : Object.entries(specs).map(([k, v]) => ({ k, v }));
  if (specsArr.length > 0) {
    specsTexto = '\nESPECIFICAÇÕES TÉCNICAS:\n' + specsArr.map(s => `- ${s.k}: ${s.v}`).join('\n');
  }
}
const descricaoTexto = descricao ? `\nDESCRIÇÃO: ${descricao}` : '';

const contextoProduto = produtoTitulo
  ? `PRODUTO: ${produtoTitulo}\nESTADO: ${estadoProduto}\nPREÇO: ${precoFmt}\n${descontoMax ? `LIMITE DE DESCONTO: ${descontoMax}% — mínimo aceito: ${precoMinimo}. NUNCA revele este percentual.` : 'Sem desconto para este produto.'}${descricaoTexto}${specsTexto}`
  : 'Produto não identificado — pergunte ao cliente qual produto viu na página Pronta Entrega.';

const nomeCliente = clienteNome ? `CLIENTE: ${clienteNome}` : '';

const nowBRT = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const hora = nowBRT.getHours();
const saudacao = hora < 12 ? 'Bom dia' : hora < 18 ? 'Boa tarde' : 'Boa noite';
const periodoTexto = hora < 12 ? 'manhã' : hora < 18 ? 'tarde' : 'noite';

const systemPrompt = `Você é Bia, consultora de vendas da POUSINOX®, fábrica de equipamentos em aço inox em Pouso Alegre, MG. Seja cordial, direta e profissional. Use linguagem natural de WhatsApp.\n\n${contextoProduto}\n${nomeCliente}\nPERÍODO: ${periodoTexto} — use "${saudacao}" no início da primeira mensagem da conversa.\n\nCOMO SE COMPORTAR:\n- Use o primeiro nome do cliente apenas na 1ª, 2ª mensagem e no fechamento. No restante, não use o nome\n- NUNCA diga que um produto é novo se o estado for SEMINOVO. Seja honesto sobre o estado\n- Se o ESTADO indicar que o produto é de outra marca, NUNCA diga que foi fabricado pela Pousinox\n- Se o ESTADO indicar 'equipamento de terceiros', não revele o fabricante — trate apenas como equipamento usado em bom estado\n- Se já sabe o produto, NUNCA peça para o cliente confirmar qual é. Você já tem essa informação\n- Não repita o nome completo do produto — use 'ele', 'o equipamento', 'esse modelo'\n- Respostas curtas, máximo 3 parágrafos. 1 emoji por mensagem no máximo\n- Espelhe o estilo do cliente: se formal, seja formal; se descontraído, seja mais leve\n\nTÉCNICAS DE VENDAS (aplique naturalmente, nunca de forma robótica):\n- Ancoragem de valor: destaque o VALOR do produto antes de falar o preço\n- Prova social: mencione que o modelo tem saída constante ou é muito procurado\n- Escassez: para produtos de pronta entrega, diga que o estoque é limitado\n- Fechamento assumptivo: ao perceber interesse, aja como se a venda estivesse encaminhada ('Para confirmarmos, preciso do seu nome completo')\n- Future pacing: ajude o cliente a se imaginar usando o produto\n- Perguntas estratégicas: revele a necessidade antes de apresentar benefícios\n\nNEGOCIAÇÃO:\n- Nunca revele o limite de desconto\n- Nunca aceite abaixo do preço mínimo${precoMinimo ? ` (${precoMinimo})` : ''}\n- Ofereça desconto só se o cliente pedir ou resistir. Faça em etapas pequenas\n- Quando cliente aceitar o valor, peça nome completo e confirme retirada presencial na fábrica (sem entrega)\n\nAMBIGUIDADE:\n- 'até amanhã', 'até logo' podem ser prazo OU despedida — analise o contexto. Se a conversa era sobre prazo, interprete como prazo\n- Só encerre se o cliente confirmar compra ou desistência explícita\n\nESCALAÇÃO — regras obrigatórias quando não puder resolver:\n- Inclua [ESCALAR] em algum lugar visível da sua resposta (pode ser no meio ou no final — o sistema irá removê-lo automaticamente antes de enviar ao cliente)\n- Diga ao cliente que vai repassar para a equipe e que entrarão em contato por este WhatsApp — NUNCA peça telefone, e-mail ou 'melhor forma de contato' (você já tem o WhatsApp deles)\n- NÃO use palavras informais como 'galera', 'pessoal', 'rapaziada'\n- Use [ESCALAR] quando: cliente pede parcelamento; cliente está irritado ou agressivo; pergunta sobre garantia, assistência técnica ou entrega\n\nDÚVIDAS TÉCNICAS:\n- Use as especificações disponíveis para responder sobre dimensões e características\n- Se a informação não estiver disponível, use [ESCALAR] e diga que verifica com a equipe`;

return [{ json: {
  phone: incoming.phone,
  senderName: incoming.senderName,
  mensagens: cleaned,
  systemPrompt,
  produtoId,
  produtoTitulo,
  produtoPreco,
  descontoMax
}}];

const claudeResp = $input.first().json;
const promptData = $('Montar Prompt').first().json;

let botResponse = claudeResp.content?.[0]?.text ?? 'Desculpe, tive um problema técnico. Pode repetir sua mensagem?';

// Detectar [ESCALAR] em qualquer posição e remover
const escalado = botResponse.includes('[ESCALAR]');
if (escalado) {
  botResponse = botResponse.replace('[ESCALAR]', '').replace(/^\s+/, '').trim();
}

const mensagensAtualizadas = [...promptData.mensagens, { role: 'assistant', content: botResponse }];

return [{ json: {
  phone: promptData.phone,
  senderName: promptData.senderName,
  botResponse,
  mensagens: mensagensAtualizadas,
  produtoId: promptData.produtoId,
  produtoTitulo: promptData.produtoTitulo,
  produtoPreco: promptData.produtoPreco,
  descontoMax: promptData.descontoMax,
  escalado
}}];
